#include <iostream>
#include <vector>
using namespace std;

struct Node {
    int data;
    Node* next;
    Node* prev;
    Node(int value) : data(value), next(nullptr), prev(nullptr) {}
};

class DoublyLinkedList {
public:
    Node* head;
    DoublyLinkedList() : head(nullptr) {}
    void push(int new_data);
    void printList();
    void deleteHead();
};

void DoublyLinkedList::push(int new_data) {
    Node* new_node = new Node(new_data);
    new_node->next = head;
    if (head != nullptr)
        head->prev = new_node;
    head = new_node;
}

void DoublyLinkedList::printList() {
    Node* node = head;
    while (node != nullptr) {
        cout << node->data << endl;
        node = node->next;
    }
}

void DoublyLinkedList::deleteHead() {
    if (head == nullptr)
        return;
    Node* temp = head;
    head = head->next;
    if (head != nullptr)
        head->prev = nullptr;
    delete temp;
}

int main() {
    int n;
    cin >> n;
    DoublyLinkedList dll;
    for (int i = 0; i < n; i++) {
        int data;
        cin >> data;
        dll.push(data);
    }
    dll.deleteHead();
    cout << (dll.head ? to_string(--n) : "0") << endl;
    dll.printList();
    return 0;
}

